function generateSuggestions(prefix, topic) {
  const suggestions = [];
  const prefixList = prefix.map(p => p ? p + " " : "");

  for (const p of prefixList) {
    const suggestion = (p + topic).trim();
    if (suggestion.length > 0 && suggestion.length <= 60) {
      suggestions.push(suggestion);
    }
  }

  return suggestions;
}

console.log("Generating prompts...");
const allPrompts = {};

const categoryNames = Object.keys(CATEGORIES);
let totalCount = 0;

for (const category of categoryNames) {
  const data = CATEGORIES[category];
  const suggestions = [];

  for (const topic of data.topics) {
    const generated = generateSuggestions(data.prefix, topic);
    suggestions.push(...generated);
  }

  // Remove duplicates
  const unique = [...new Set(suggestions)];
  allPrompts[category] = unique;
  totalCount += unique.length;
  console.log(`Generated ${unique.length} prompts for ${category}`);
}

console.log(`\nTotal: ${totalCount} prompts`);

// Save to file
fs.writeFileSync('./data/prompts.json', JSON.stringify(allPrompts, null, 2));
console.log('Saved to data/prompts.json');